using Avalonia;
using Avalonia.Controls;
using Avalonia.Threading;
using Avalonia.VisualTree;
using VisualRelay.App.ViewModels;
using VisualRelay.App.Views;
using VisualRelay.App.Views.Controls;

namespace VisualRelay.Tests;

/// <summary>
/// Regression anchor for the ACTIVITY panel title vertical misalignment.
///
/// Root cause: the ACTIVITY &quot;panelTitle&quot; TextBlock sits in the same
/// Auto-height header row as the taller &quot;Reveal&quot; button (and the
/// collapse toggle), but unlike the Queue panel's title — which sets
/// VerticalAlignment=&quot;Center&quot; — the ACTIVITY title had no
/// VerticalAlignment, so it rendered top-aligned relative to the button.
///
/// Fix: add VerticalAlignment=&quot;Center&quot; to the ACTIVITY panelTitle
/// TextBlock so it matches the Queue panel and sits level with the Reveal
/// button.
/// </summary>
[Collection("Headless")]
public sealed class ActivityColumnTitleLayoutTests
{
    /// <summary>
    /// The ACTIVITY panelTitle TextBlock must have
    /// VerticalAlignment=&quot;Center&quot; so it aligns vertically with the
    /// taller Reveal button in the same Auto-height header row (matching the
    /// Queue panel pattern at QueuePanel.axaml:18).
    ///
    /// This is a structural property check — no layout measurement needed.
    /// </summary>
    [AvaloniaFact]
    public void ActivityTitle_HasVerticalAlignmentCenter()
    {
        var vm = new MainWindowViewModel();
        var window = new MainWindow
        {
            DataContext = vm,
            Width = 1440,
            Height = 900
        };
        window.Show();
        Dispatcher.UIThread.RunJobs();

        var activityColumn = window.GetVisualDescendants()
            .OfType<ActivityColumn>()
            .Single();

        // Find the panelTitle TextBlock with text "ACTIVITY".
        TextBlock? titleBlock = null;
        foreach (var descendant in activityColumn.GetVisualDescendants().OfType<TextBlock>())
        {
            if (descendant.Classes.Contains("panelTitle") && descendant.Text == "ACTIVITY")
            {
                titleBlock = descendant;
                break;
            }
        }

        Assert.NotNull(titleBlock);
        Assert.Equal(VerticalAlignment.Center, titleBlock!.VerticalAlignment);
    }

    /// <summary>
    /// Visual guard: the ACTIVITY title's vertical midpoint must be within
    /// 4 px of the Reveal button's vertical midpoint in the same header row.
    /// This catches any regression that would reintroduce top-alignment even
    /// if the structural VerticalAlignment property were somehow present.
    /// </summary>
    [AvaloniaFact]
    public void ActivityTitle_IsVerticallyAlignedWithRevealButton()
    {
        var vm = new MainWindowViewModel();
        var window = new MainWindow
        {
            DataContext = vm,
            Width = 1440,
            Height = 900
        };
        window.Show();
        Dispatcher.UIThread.RunJobs();

        var activityColumn = window.GetVisualDescendants()
            .OfType<ActivityColumn>()
            .Single();

        // Find the panelTitle TextBlock ("ACTIVITY").
        TextBlock? titleBlock = null;
        foreach (var descendant in activityColumn.GetVisualDescendants().OfType<TextBlock>())
        {
            if (descendant.Classes.Contains("panelTitle") && descendant.Text == "ACTIVITY")
            {
                titleBlock = descendant;
                break;
            }
        }
        Assert.NotNull(titleBlock);

        // Find the Reveal button in the same header row.
        Button? revealButton = null;
        foreach (var descendant in activityColumn.GetVisualDescendants().OfType<Button>())
        {
            if (descendant.Content?.ToString() == "Reveal")
            {
                revealButton = descendant;
                break;
            }
        }
        Assert.NotNull(revealButton);

        // Translate both to a common ancestor (the ActivityColumn) and compare
        // their vertical midpoints.
        var titleMidY = MidYInAncestor(titleBlock!, activityColumn);
        var buttonMidY = MidYInAncestor(revealButton!, activityColumn);

        Assert.True(Math.Abs(titleMidY - buttonMidY) <= 4.0,
            $"ACTIVITY title mid-Y ({titleMidY:F1}) and Reveal button mid-Y ({buttonMidY:F1}) " +
            "differ by more than 4 px. The title must be vertically centered relative to the button.");
    }

    private static double MidYInAncestor(Visual child, Visual ancestor)
    {
        var point = child.TranslatePoint(
            new Point(child.Bounds.Width / 2, child.Bounds.Height / 2), ancestor);
        Assert.NotNull(point);
        return point!.Value.Y;
    }
}

using Avalonia;
using Avalonia.Controls;
using Avalonia.Threading;
using Avalonia.VisualTree;
using VisualRelay.App.ViewModels;
using VisualRelay.App.Views;
using VisualRelay.App.Views.Controls;

namespace VisualRelay.Tests;

/// <summary>
/// Regression anchor for the attachment Reveal button spacing defect.
///
/// Root cause: when the attachment item template was changed from a Grid
/// (which had ColumnSpacing=&quot;6&quot;) to a DockPanel, the Reveal
/// button kept a Margin of &quot;0,0,6,0&quot; — a gap only on its right.
/// The file-path TextBlock (the DockPanel fill child) sits directly against
/// the left edge of the Reveal button with no gap, causing the trimmed
/// filename to butt against the button.
///
/// Fix: give the Reveal button Margin=&quot;6,0,6,0&quot; to restore the
/// ~6 px gap between the path text and the button.
/// </summary>
[Collection("Headless")]
public sealed class TaskDetailAttachmentRevealButtonLayoutTests
{
    /// <summary>
    /// The Reveal button in the attachment item template must have a left
    /// margin of at least 6 px so the file-path TextBlock (the DockPanel
    /// fill child that sits to its left) does not butt directly against it.
    ///
    /// This is a structural property check — the Margin.Left guards the gap
    /// independently of layout measurements.
    /// </summary>
    [AvaloniaFact]
    public async Task AttachmentRevealButton_MarginLeft_IsSixOrMore()
    {
        // ── Arrange: task with an attachment ──
        using var repo = TestRepository.Create();
        repo.WriteConfig("dotnet test", []);

        repo.WriteNestedTask("gap-check", "# Gap Check\n", [("file.txt", "content")]);

        var viewModel = new MainWindowViewModel { RootPath = repo.Root };
        await viewModel.LoadInitialAsync();

        viewModel.SelectedTask = viewModel.Tasks.Single(t => t.Id == "gap-check");
        viewModel.SelectedTabIndex = 2; // Attachments tab
        Dispatcher.UIThread.RunJobs();

        var window = new MainWindow
        {
            DataContext = viewModel,
            Width = 900,
            Height = 900
        };
        window.Show();
        Dispatcher.UIThread.RunJobs();

        // ── Locate the Reveal button inside the Attachments ScrollViewer ──
        var taskDetailPanel = window.GetVisualDescendants()
            .OfType<TaskDetailPanel>()
            .Single();

        Button? revealButton = null;
        foreach (var sv in taskDetailPanel.GetVisualDescendants().OfType<ScrollViewer>())
        {
            var btn = sv.GetVisualDescendants()
                .OfType<Button>()
                .FirstOrDefault(b => b.Content?.ToString() == "Reveal");
            if (btn is not null)
            {
                revealButton = btn;
                break;
            }
        }

        Assert.NotNull(revealButton);

        // ── Assertion: left margin ≥ 6 ──
        Assert.True(
            revealButton!.Margin.Left >= 6,
            $"Reveal button Margin.Left is {revealButton.Margin.Left}, " +
            "must be ≥ 6.  A zero left margin causes the file-path TextBlock " +
            "to butt directly against the Reveal button with no gap.");
    }

    /// <summary>
    /// Visual guard: the rendered horizontal gap between the file-path
    /// TextBlock's right edge and the Reveal button's left edge must be at
    /// least 4 px (allowing for rounding).  This catches any regression
    /// that would shrink the gap even if the Margin property were somehow
    /// present.
    /// </summary>
    [AvaloniaFact]
    public async Task AttachmentFilePath_HasGapBeforeRevealButton()
    {
        // ── Arrange: task with an attachment whose path is long enough to
        //    exercise the ellipsis-and-gap region ──
        using var repo = TestRepository.Create();
        repo.WriteConfig("dotnet test", []);

        var longName = "very-long-attachment-filename-that-would-overlap-with-reveal-button.txt";
        repo.WriteNestedTask("gap-visual", "# Gap Visual\n", [(longName, "content")]);

        var viewModel = new MainWindowViewModel { RootPath = repo.Root };
        await viewModel.LoadInitialAsync();

        viewModel.SelectedTask = viewModel.Tasks.Single(t => t.Id == "gap-visual");
        viewModel.SelectedTabIndex = 2; // Attachments tab
        Dispatcher.UIThread.RunJobs();

        var window = new MainWindow
        {
            DataContext = viewModel,
            Width = 900,
            Height = 900
        };
        window.Show();
        Dispatcher.UIThread.RunJobs();

        // ── Locate the path TextBlock and Reveal button ──
        var taskDetailPanel = window.GetVisualDescendants()
            .OfType<TaskDetailPanel>()
            .Single();

        TextBlock? pathBlock = null;
        Button? revealButton = null;

        foreach (var sv in taskDetailPanel.GetVisualDescendants().OfType<ScrollViewer>())
        {
            var blocks = sv.GetVisualDescendants()
                .OfType<TextBlock>()
                .Where(tb => tb.Text == longName)
                .ToList();
            var btns = sv.GetVisualDescendants()
                .OfType<Button>()
                .Where(b => b.Content?.ToString() == "Reveal")
                .ToList();

            if (blocks.Count > 0 && btns.Count > 0)
            {
                pathBlock = blocks[0];
                revealButton = btns[0];
                break;
            }
        }

        Assert.NotNull(pathBlock);
        Assert.NotNull(revealButton);

        // Translate both edges to a common ancestor.
        var commonAncestor = pathBlock!.Parent as DockPanel;
        Assert.NotNull(commonAncestor);

        var pathRightEdge = pathBlock.TranslatePoint(
            new Point(pathBlock.Bounds.Width, 0), commonAncestor);
        var buttonLeftEdge = revealButton!.TranslatePoint(
            new Point(0, 0), commonAncestor);

        Assert.NotNull(pathRightEdge);
        Assert.NotNull(buttonLeftEdge);

        var gap = buttonLeftEdge!.Value.X - pathRightEdge!.Value.X;

        Assert.True(gap >= 4.0,
            $"Gap between file-path right edge and Reveal button left edge is {gap:F1} px, " +
            "must be ≥ 4 px. The path text is butting against the Reveal button.");
    }
}

